	.TITLE	T.ASM	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SMAKY	.REF	MODULES	.LOC	0OCHDBOX:.BLKB	2		; canal module DBOXLGVAR:	.LOC	0START:	LIB	?OPELIB	LOAD.W	D3,#2	LIB	?MOUSE	LOAD.L	A6,#R16"VAR	LOAD.L	A3,#R16"NMDBOX	LOAD.W	D3,#DBOX_FIRST	LIB_	OPEN	JUMP,NE ERFAT1	LOAD.W	(A6)+OCHDBOX,D1	CALL	DBOXQQERFAT:	LOAD.W	D1,(A6)+OCHDBOX	LIB_	CLOSEERFAT1:	LIB	?CLOLIB	FOS	?STOP;;?	EXITDBOXQQ:	LOAD.L	D4,#B'0101	LOAD.L	A2,#R16"TDBOX_QQ	LOAD.W	D2,#2^BDBSAV	; D2 <-- mode	DBOX_	OPEN		; ouvre la DBOX	JUMP,NE	90$20$:	DBOX_	EDIT		; attend une action ...	LOAD.L	A1,#R16"TKEY_QQ	LOAD.W	D1,#2^BDBCCMM!2^BDBCCFF	DBOX_	CALLC	COMP.W	D3,#KEYMGR	; bouton souris relach ?	JUMP,EQ	20$		; oui => 20$	COMP.W	D3,#CR		; D'ACCORD ?	JUMP,EQ 80$	COMP.W	D3,#END		; ANNULE ?	JUMP,EQ 80$	COMP.W	D3,#'G	JUMP,EQ 50$	COMP.W	D3,#'g	JUMP,EQ 50$	COMP.W	D3,#'F	JUMP,EQ 60$	COMP.W	D3,#'f	JUMP,EQ 60$30$:	LOAD.B	D3,#BIPLIT	LIB	?BEEP		; p'tit bruit	JUMP	20$50$:	LIB	?GETCAR	COMP.W	D3,#'0	JUMP,LO 30$	COMP.W	D3,#'9	JUMP,HI 30$	SUB.W	D3,#'0	LOAD.W	D2,D3	TSET.L	D2:#14	PUSH.L	D4	DBOX_	GETCO	POP.L	D4	JUMP	20$60$:	LIB	?GETCAR	COMP.W	D3,#'0	JUMP,LO 30$	COMP.W	D3,#'9	JUMP,HI 30$	SUB.W	D3,#'0	LOAD.W	D2,D3	TSET.L	D2:#13	PUSH.L	D4	DBOX_	GETCO	POP.L	D4	JUMP	20$80$:	DBOX_	CLOSE		; ferme la DBOX90$:	RETTDBOX_QQ:	.W	10$-TDBOX_QQ	.W	20$-TDBOX_QQ	.W	0,010$:	.B	ODBSQUARE,0	.ASCIZ	"  gras"	.B	ODBCR	.B	ODBSQUARE,1	.ASCIZ	"  italique"	.B	ODBCR	.B	ODBLCIRCLE,2	.ASCIZ	"  relief"	.B	ODBCR	.B	ODBLCIRCLE,3	.ASCIZ	"  ombr"	.B	ODBCR,ODBCR	.B	ODBCIRCLE,4	.ASCIZ	"  largeur    x 2"	.B	ODBCR,ODBCR,ODBCR	.B	ODBBOX,0,CR,TDBMEV	.ASCIZ	" TRANSFORME "	.B	ODBTEXT	.ASCIZ	"   "	.B	ODBBOX,0,END,TDBNORM	.ASCIZ	"   ANNULE   "	.B	020$:	.ASCIZ	""	.ASCIZ	""		;     ;     ;     ;	.ASCIZ	""	.ASCIZ	"Transforme"		;     ;     ;     ;	.ASCIZ	""	.ASCIZ	""		;     ;     ;     ;	.ASCIZ	""	.ASCIZ	""		;     ;     ;     ;	.ASCIZ	""	.ASCIZ	""		;     ;     ;     ;	.ASCIZ	""	.ASCIZ	"Annule"	.EVENTKEY_QQ:	.W	F1,F2,F3,CR,0		DOKCR-TKEY_QQ	.W	F0,END,0		DOKEND-TKEY_QQ	.W	KEYMGR,KEYMMR,KEYMDR,0	DOKMGR-TKEY_QQ	.W	0DOKCR:	LOAD.W	D3,#CR	RETDOKEND:	LOAD.W	D3,#END	RETDOKMGR:	LOAD.W	D3,#KEYMGR	RETNMDBOX:	.ASCIZ	"DBOX"	.EVENVAR:	.FILLB	LGVAR,0	.END	START